SELECT /* base.ec.od :: OdCart :: selectList */ c.* , ste.site_nm AS site_nm , mem.member_nm AS member_nm , prd.prod_nm AS prod_nm , oi1.opt_nm AS opt_nm1 , oi2.opt_nm AS opt_nm2 FROM od_cart c LEFT JOIN sy_site ste ON ste.site_id = c.site_id LEFT JOIN mb_member mem ON mem.member_id = c.member_id LEFT JOIN pd_prod prd ON prd.prod_id = c.prod_id LEFT JOIN pd_prod_opt_item oi1 ON oi1.opt_item_id = c.opt_item_id_1 LEFT JOIN pd_prod_opt_item oi2 ON oi2.opt_item_id = c.opt_item_id_2
ORDER BY c.cart_id ASC ORDER BY c.cart_id DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

