site_id = #{siteId}, member_id = #{memberId}, session_key = #{sessionKey}, prod_id = #{prodId}, sku_id = #{skuId}, opt_item_id_1 = #{optItemId1}, opt_item_id_2 = #{optItemId2}, unit_price = #{unitPrice}, order_qty = #{orderQty}, item_price = #{itemPrice}, is_checked = #{isChecked}, upd_by = #{updBy}, upd_date = #{updDate},
